#!/usr/bin/env node
/**
 * Register Claude Code skills from the active Harnessy skills root.
 * Auto-generated by flow-install.
 */
import { GLOBAL_SKILLS_DIR, listActiveSkills, registerClaudeSkills } from "./agents.mjs";

const run = async () => {
  const skills = await listActiveSkills(GLOBAL_SKILLS_DIR);
  const count = await registerClaudeSkills(skills);
  console.log("Claude Code refreshed for " + count + " skill(s)");
};

run().catch((e) => {
  console.error("Claude registration failed:", e);
  process.exitCode = 1;
});
